#include <bits/stdc++.h>
using namespace std;
const int N=6005;
int n,dp[N][2],a[N],fa[N],vis[N];
vector<int> son[N];

void dfs(int x)
{
    dp[x][1]=a[x];
    for(int i=0;i<son[x].size();i++)
    {
        int t=son[x][i];
        dfs(t);
        dp[x][0]+=max(dp[t][0],dp[t][1]);
        dp[x][1]+=dp[t][0];
    }
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    int root;
    for(int i=1;i<n;i++)
    {
        int x,y;
        cin>>x>>y;
        fa[x]=y;
        vis[x]=1;
        son[y].push_back(x);
    }
    for(int i=1;i<=n;i++)
    {
        if(vis[i]==0)
        {
            root=i;
            break;
        }
    }
    dfs(root);
    cout<<max(dp[root][0],dp[root][1]);
    return 0;
}
